const body = $input.first().json.body;
const token = body.token;

if (token !== 'pmtx_img_2026') {
  return [{ json: { error: true, message: 'Unauthorized', status: 401 } }];
}

const products = body.products;
const marketplace = body.marketplace || 'sprinter_es';

if (!products || !Array.isArray(products) || products.length === 0) {
  return [{ json: { error: true, message: 'No products provided', status: 400 } }];
}

const invalid = products.filter(p => !p.sku || !p.image_url);
if (invalid.length > 0) {
  return [{ json: { error: true, message: 'Products missing sku or image_url: ' + invalid.map(p => p.sku || 'unknown').join(', '), status: 400 } }];
}

return [{ json: { error: false, products, marketplace, total: products.length } }];

const input = $input.first().json;

if (input.error) {
  return [{ json: input }];
}

const products = input.products;
const marketplace = input.marketplace;

const IMGPROXY_HOST = 'imgproxy.reyl9a.easypanel.host';
const R2_HOST = '1ad99f42539d9623984dd787e28151ba.r2.cloudflarestorage.com';
const R2_BUCKET = 'sprinter-images';
const R2_ACCESS_KEY = '81e11f2adc76f7cb3da11063e4f2d9d4';
const R2_SECRET_KEY = '1172046df1975dea35c76f7d73df05669cc9a331ce1f1b0620225e73eb257265';
const CDN_BASE = 'https://pub-3dd3844245694c3f82abf1a5f3f07c43.r2.dev';

const { createHmac, createHash } = require('crypto');
const https = require('https');

function hmacSHA256(key, data) {
  return createHmac('sha256', key).update(data).digest();
}

function sha256hex(data) {
  return createHash('sha256').update(data).digest('hex');
}

function httpsGet(hostname, path) {
  return new Promise((resolve, reject) => {
    const req = https.request({ hostname, path, port: 443, method: 'GET' }, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        const loc = res.headers.location;
        const match = loc.match(/^https:\/\/([^/]+)(\/.*)$/);
        if (match) {
          httpsGet(match[1], match[2]).then(resolve).catch(reject);
        } else {
          reject(new Error('Bad redirect: ' + loc));
        }
        return;
      }
      const chunks = [];
      res.on('data', (chunk) => chunks.push(chunk));
      res.on('end', () => resolve({ status: res.statusCode, data: Buffer.concat(chunks) }));
    });
    req.on('error', reject);
    req.setTimeout(60000, () => { req.destroy(); reject(new Error('Timeout')); });
    req.end();
  });
}

function httpsPut(hostname, path, headers, body) {
  return new Promise((resolve, reject) => {
    const req = https.request({ hostname, path, port: 443, method: 'PUT', headers }, (res) => {
      const chunks = [];
      res.on('data', (chunk) => chunks.push(chunk));
      res.on('end', () => resolve({ status: res.statusCode, data: Buffer.concat(chunks) }));
    });
    req.on('error', reject);
    req.setTimeout(60000, () => { req.destroy(); reject(new Error('Timeout')); });
    req.write(body);
    req.end();
  });
}

const results = [];
const errors = [];
const cdnUrls = [];
const previews = [];

for (let i = 0; i < products.length; i++) {
  const product = products[i];
  const sku = product.sku;

  try {
    const imgproxyPath = '/insecure/rs:fit:1000:1000:1/bg:FFFFFF/pd:250:0:250:0/format:jpg/quality:90/plain/' + encodeURIComponent(product.image_url);

    const imgResponse = await httpsGet(IMGPROXY_HOST, imgproxyPath);
    if (imgResponse.status !== 200) {
      throw new Error('imgproxy HTTP ' + imgResponse.status);
    }
    const imageBuffer = imgResponse.data;
    const objectKey = 'sprinter/' + sku.toLowerCase().replace(/[^a-z0-9-_]/g, '-') + '.jpg';

    const now = new Date();
    const dateStamp = now.toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z';
    const shortDate = dateStamp.substring(0, 8);
    const region = 'auto';
    const svc = 's3';
    const payloadHash = sha256hex(imageBuffer);
    const canonicalUri = '/' + R2_BUCKET + '/' + objectKey;

    const NL = String.fromCharCode(10);
    const canonicalHeaders = 'content-type:image/jpeg' + NL + 'host:' + R2_HOST + NL + 'x-amz-content-sha256:' + payloadHash + NL + 'x-amz-date:' + dateStamp + NL;
    const signedHeaders = 'content-type;host;x-amz-content-sha256;x-amz-date';
    const canonicalRequest = 'PUT' + NL + canonicalUri + NL + NL + canonicalHeaders + NL + signedHeaders + NL + payloadHash;

    const credentialScope = shortDate + '/' + region + '/' + svc + '/aws4_request';
    const stringToSign = 'AWS4-HMAC-SHA256' + NL + dateStamp + NL + credentialScope + NL + sha256hex(canonicalRequest);

    const signingKey = hmacSHA256(hmacSHA256(hmacSHA256(hmacSHA256('AWS4' + R2_SECRET_KEY, shortDate), region), svc), 'aws4_request');
    const signature = createHmac('sha256', signingKey).update(stringToSign).digest('hex');

    const authHeader = 'AWS4-HMAC-SHA256 Credential=' + R2_ACCESS_KEY + '/' + credentialScope + ', SignedHeaders=' + signedHeaders + ', Signature=' + signature;
    const uploadPath = '/' + R2_BUCKET + '/' + objectKey;

    const uploadResponse = await httpsPut(R2_HOST, uploadPath, {
      'Content-Type': 'image/jpeg',
      'Host': R2_HOST,
      'x-amz-content-sha256': payloadHash,
      'x-amz-date': dateStamp,
      'Authorization': authHeader,
      'Content-Length': imageBuffer.length
    }, imageBuffer);

    if (uploadResponse.status !== 200) {
      throw new Error('R2 HTTP ' + uploadResponse.status + ': ' + uploadResponse.data.toString().substring(0, 200));
    }

    const cdnUrl = CDN_BASE + '/' + objectKey;
    cdnUrls.push({ sku, cdnUrl });
    results.push({ sku, title: product.title || '', brand: product.brand || '', original_url: product.image_url, cdn_url: cdnUrl, status: 'success' });
    if (previews.length < 4) { previews.push({ sku, original: product.image_url, converted: cdnUrl }); }

  } catch (err) {
    errors.push({ sku, error: err.message });
    results.push({ sku, title: product.title || '', original_url: product.image_url, cdn_url: '', status: 'error', error: err.message });
  }
}

return [{ json: { error: false, success: results.filter(r => r.status === 'success').length, errors: errors.length, total: products.length, previews, errorList: errors, cdnUrls, results, marketplace } }];

const data = $input.first().json;
if (data.error) { return [{ json: data }]; }

const results = data.results.filter(r => r.status === 'success');
const NL = String.fromCharCode(10);
const csvHeaders = ['sku', 'title', 'brand', 'image_url_1', 'original_url', 'status'];
const csvRows = results.map(r => [r.sku, '"' + (r.title || '').replace(/"/g, '""') + '"', '"' + (r.brand || '').replace(/"/g, '""') + '"', r.cdn_url, r.original_url, r.status].join(';'));
const csvContent = csvHeaders.join(';') + NL + csvRows.join(NL);
const csvBase64 = Buffer.from(csvContent, 'utf-8').toString('base64');
const filename = 'mirakl_images_' + data.marketplace + '_' + new Date().toISOString().split('T')[0] + '.csv';

return [{ json: { error: false, csvBase64, csvFilename: filename, imagesProcessed: data.total, success: data.success, errors: data.errors, previews: data.previews, errorList: data.errorList, cdnUrls: data.cdnUrls } }];

